/**
 * @param {number[][]} grid
 * @return {number}
 */
function solve(grid) {
    const m = grid.length;
    const n = grid[0].length;

    // The problem constraints state m * n <= 1000.
    // Since we only move right or down, any path from (0, 0) to (m-1, n-1)
    // has a fixed length of (m - 1) + (n - 1) + 1 = m + n - 1 steps (m+n-1 cells).
    // The number of paths is C(m+n-2, m-1), which can be large.

    // However, the state space defined by (i, j) where i + j = k (the sum of indices)
    // suggests dynamic programming based on the total number of steps taken.
    // The total number of steps is k = i + j. The maximum k is m - 1 + n - 1 = m + n - 2.

    // Since the grid values are small (0 to 1023, or 10 bits),
    // we can use DP where the state keeps track of the achievable XOR values.

    // dp[k] will be a Set storing all possible XOR sums achievable at any cell (i, j)
    // such that i + j = k.
    // k ranges from 0 to m + n - 2.
    const maxSteps = m + n - 2;
    const dp = new Array(maxSteps + 1);
    for (let k = 0; k <= maxSteps; k++) {
        dp[k] = new Set();
    }

    // Initialization: At step k=0, only (0, 0) is reachable.
    dp[0].add(grid[0][0]);

    for (let k = 0; k < maxSteps; k++) {
        const currentXorSet = dp[k];
        if (currentXorSet.size === 0) continue;

        // Iterate over all cells (i, j) such that i + j = k.
        // i ranges from max(0, k - (n - 1)) to min(m - 1, k).
        const startI = Math.max(0, k - (n - 1));
        const endI = Math.min(m - 1, k);

        // We need to associate the XOR sum with the specific cell (i, j)
        // because the next possible moves depend on (i, j).
        // The standard DP approach here is to transition cell by cell,
        // not layer by layer (by k = i+j), because we need the specific grid value.

        // Let's redefine DP based on coordinates:
        // dp[i][j] = Set of all possible XOR sums reaching (i, j).

        // Re-initialize DP structure:
        const dpCoord = Array(m).fill(0).map(() => Array(n).fill(0).map(() => new Set()));

        // Base case
        dpCoord[0][0].add(grid[0][0]);

        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (i === 0 && j === 0) continue;

                const currentValue = grid[i][j];
                const reachableXors = new Set();

                // 1. From above (i-1, j)
                if (i > 0) {
                    for (const prevXor of dpCoord[i - 1][j]) {
                        reachableXors.add(prevXor ^ currentValue);
                    }
                }

                // 2. From left (i, j-1)
                if (j > 0) {
                    for (const prevXor of dpCoord[i][j - 1]) {
                        reachableXors.add(prevXor ^ currentValue);
                    }
                }

                dpCoord[i][j] = reachableXors;
            }
        }

        // The result is the minimum value in the set at the bottom-right corner.
        const finalXors = dpCoord[m - 1][n - 1];
        let minXor = Infinity;

        if (finalXors.size > 0) {
            for (const xorSum of finalXors) {
                if (xorSum < minXor) {
                    minXor = xorSum;
                }
            }
        }

        return minXor;
    }
}

