import scala.collection.mutable

object Solution {
  /**
   * @param grid The m x n integer grid.
   * @return The minimum possible XOR sum.
   */
  def solve(grid: Array[Array[Int]]): Int = {
    val m = grid.length
    val n = grid(0).length

    // dp[i][j] stores a Set of all possible XOR sums reaching cell (i, j).
    // Using mutable.Array for efficiency in this DP approach.
    val dp = Array.ofDim[mutable.Set[Int]](m)
    for (i <- 0 until m) {
      dp(i) = Array.fill(n)(mutable.Set.empty[Int])
    }

    // Base case: (0, 0)
    dp(0)(0) = mutable.Set(grid(0)(0))

    for (i <- 0 until m) {
      for (j <- 0 until n) {
        if (i == 0 && j == 0) continue

        val currentValue = grid(i)(j)
        val reachableXors = mutable.Set.empty[Int]

        // 1. From above (i-1, j)
        if (i > 0) {
          for (prevXor <- dp(i - 1)(j)) {
            reachableXors += (prevXor xor currentValue)
          }
        }

        // 2. From left (i, j-1)
        if (j > 0) {
          for (prevXor <- dp(i)(j - 1)) {
            reachableXors += (prevXor xor currentValue)
          }
        }

        dp(i)(j) = reachableXors
      }
    }

    // The result is the minimum value in the set at the bottom-right corner.
    val finalXors = dp(m - 1)(n - 1)

    if (finalXors.isEmpty) {
      // Should not happen given problem constraints (m>=1, n>=1)
      return 0 
    } else {
      finalXors.min
    }
  }
}
